// Path 2: offline per-word measured-FFN-compute table over the WordNet swap universe.
// For each candidate word, probe its input-dependent FFN active_blocks in a FIXED carrier under an
// aggressive skip mode → a word→compute table so preconditioning needs no in-context probing later.
// Resume-aware + checkpointed. Usage: node compute-table.mjs [port] [maxWords]
import fs from 'fs';
const HOME = process.env.HOME;
const PORT = process.argv[2] || '8100';
const MAX = process.argv[3] ? parseInt(process.argv[3], 10) : Infinity;
const OUT = `${HOME}/.flux-embed/compute-table.json`;

const vocab = JSON.parse(fs.readFileSync('./apps/edge-workers/vocab-cache/qwen3-8b-temp-vocab.json')).vocab;
const vset = new Set(Object.keys(vocab));
const tok = (t) => { const ids=[]; for (const w of t.toLowerCase().split(/\s+/)) { let s='Ġ'+w; while (s.length) { let took=''; for (let l=Math.min(s.length,24);l>=1;l--){const c=s.slice(0,l);if(vset.has(c)){took=c;break;}} if(!took){s=s.slice(1);continue;} ids.push(vocab[took]); s=s.slice(took.length);} } return ids; };
const probe = async (t) => {
  const ids = tok(t); const body = new Uint8Array(ids.length*4); const dv = new DataView(body.buffer);
  ids.forEach((id,i)=>dv.setUint32(i*4,id>>>0,true));
  const j = await (await fetch(`http://127.0.0.1:${PORT}/precond-probe`, { method:'POST', headers:{'X-Max-New':'1','X-FFN-Leakage-Mode':'mask-input-low-70'}, body })).json();
  return j.forwards ? (j.active_input + j.active_hidden) / j.forwards : null;
};

// swap universe = WordNet headwords + their synonyms, single-token (Ġword) only
const SYN = JSON.parse(fs.readFileSync(`${HOME}/.flux-embed/synonyms.json`,'utf8'));
const universe = new Set();
for (const [head, e] of Object.entries(SYN)) {
  for (const w of [head, ...(e.n||[]), ...(e.v||[]), ...(e.a||[]), ...(e.r||[])]) {
    const lw = String(w).toLowerCase();
    if (/^[a-z]{3,}$/.test(lw) && vset.has('Ġ'+lw)) universe.add(lw);
  }
}
const words = [...universe].sort();
const table = fs.existsSync(OUT) ? JSON.parse(fs.readFileSync(OUT,'utf8')) : {};
const todo = words.filter((w)=>table[w]===undefined).slice(0, MAX);
console.log(`universe ${words.length} · already ${Object.keys(table).length} · todo ${todo.length} · port ${PORT}`);

let done = 0;
for (const w of todo) {
  try { const v = await probe(`the matter was quite ${w} indeed`); if (v!=null) table[w] = Math.round(v*10)/10; }
  catch (e) { /* leave undefined → retried next run */ }
  if (++done % 200 === 0) { fs.writeFileSync(OUT, JSON.stringify(table)); console.log(`  ${done}/${todo.length} (table ${Object.keys(table).length})`); }
}
fs.writeFileSync(OUT, JSON.stringify(table));
const vals = Object.values(table).sort((a,b)=>a-b);
console.log(`DONE table=${vals.length} → ${OUT}`);
if (vals.length) console.log(`  compute/fwd: min ${vals[0]} · median ${vals[Math.floor(vals.length/2)]} · max ${vals[vals.length-1]}`);
